import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './DoctorList.css';

const DoctorList = () => {
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecialization, setSelectedSpecialization] = useState('');
  const [specializations, setSpecializations] = useState([]);

  useEffect(() => {
    fetchDoctors();
  }, []);

  useEffect(() => {
    if (doctors.length > 0) {
      const uniqueSpecializations = [...new Set(doctors.map(doctor => doctor.specialization))];
      setSpecializations(uniqueSpecializations);
    }
  }, [doctors]);

  const fetchDoctors = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/doctors');
      setDoctors(response.data);
      setLoading(false);
    } catch (error) {
      setError('Error fetching doctors');
      setLoading(false);
    }
  };

  const filteredDoctors = doctors.filter(doctor => {
    const matchesSearch = doctor.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      doctor.specialization.toLowerCase().includes(searchTerm.toLowerCase()) ||
      doctor.qualification.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesSpecialization = selectedSpecialization === '' || 
      doctor.specialization === selectedSpecialization;

    return matchesSearch && matchesSpecialization;
  });

  if (loading) return <div className="loading">Loading...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="doctor-list">
      <div className="doctor-list-header">
        <h2>Our Doctors</h2>
        <div className="filters">
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search doctors by name, specialization..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="specialization-filter">
            <select
              value={selectedSpecialization}
              onChange={(e) => setSelectedSpecialization(e.target.value)}
            >
              <option value="">All Specializations</option>
              {specializations.map((spec) => (
                <option key={spec} value={spec}>{spec}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="doctors-grid">
        {filteredDoctors.map((doctor) => (
          <div key={doctor._id} className="doctor-card">
            <div className="doctor-image">
              <img src={doctor.image || 'https://via.placeholder.com/150'} alt={doctor.name} />
            </div>
            <div className="doctor-info">
              <h3>Dr. {doctor.name}</h3>
              <p className="specialization">{doctor.specialization}</p>
              <p className="qualification">{doctor.qualification}</p>
              <p className="experience">{doctor.experience} years of experience</p>
              <p className="consultation-fee">Consultation Fee: ${doctor.consultationFee}</p>

              <div className="contact-info">
                <p><i className="fas fa-envelope"></i> {doctor.email}</p>
                <p><i className="fas fa-phone"></i> {doctor.phone}</p>
              </div>

              <div className="available-days">
                <h4>Available Days:</h4>
                <div className="days-grid">
                  {doctor.availableDays.map((day) => (
                    <span key={day} className="day-badge">{day}</span>
                  ))}
                </div>
              </div>

              <div className="time-slots">
                <h4>Time Slots:</h4>
                <div className="slots-grid">
                  {doctor.timeSlots.map((slot, index) => (
                    <span key={index} className="time-badge">{slot}</span>
                  ))}
                </div>
              </div>

              <div className="doctor-actions">
                <Link 
                  to={`/?doctor=${doctor._id}`}
                  className="book-appointment-btn primary"
                >
                  Book Appointment
                </Link>
                <Link 
                  to={`/doctors/${doctor._id}/schedule`}
                  className="view-schedule-btn secondary"
                >
                  View Schedule
                </Link>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredDoctors.length === 0 && (
        <div className="no-results">
          <p>No doctors found matching your criteria.</p>
        </div>
      )}
    </div>
  );
};

export default DoctorList;
